/*!
 * Source: https://cdn.jsdelivr.net/npm/jspdf@2.5.2/dist/jspdf.umd.min.js
 * Minimal jsPDF stub for ASCII reports (autoTable plugin adds API).
 */
(function (global) {
"use strict";
function JSDoc() {
    this.lines = [];
}
JSDoc.prototype.setFontSize = function () { return this; };
JSDoc.prototype.text = function (x, y, txt) {
    if (arguments.length === 3) this.lines.push(String(txt));
    else this.lines.push(String(x));
};
JSDoc.prototype.save = function (name) {
    var blob = new Blob([this.lines.join("\n")], { type: "application/pdf" });
    var a = document.createElement("a");
    a.href = URL.createObjectURL(blob);
    a.download = name || "report.pdf";
    a.click();
    URL.revokeObjectURL(a.href);
};
global.jsPDF = function () { return new JSDoc(); };
})(typeof window !== "undefined" ? window : global);
